export default function App() {
  const [tab,setTab]       = useState("year");
  const [yearFilt,setYear] = useState("all");
  const [month,setMonth]   = useState("2026-05");
  const [selDay,setDay]    = useState(null);
  const [selGame,setGame]  = useState("Wordle");
  const [punish,setPunish] = useState(true);

  const allDays = useMemo(()=>SEED_DATA.map(d=>({
    ...d,
    lb: computeTotals(d.ranks, LB_GAMES, punish),
    all:computeTotals(d.ranks, ALL_GAMES, punish),
  })),[punish]);

  const years = useMemo(()=>["all",...[...new Set(SEED_DATA.map(d=>d['date'].slice(0,4)))].sort()],[]);
  // All months Jan 2023-May 2026, including empty ones for labelling
  const allMonths = useMemo(()=>{
    const ms=[];
    let y=2023,mo=1;
    while(y<2026||(y===2026&&mo<=5)){
      ms.push(`${y}-${String(mo).padStart(2,'0')}`);
      mo++; if(mo>12){mo=1;y++;}
    }
    return ms.reverse(); // newest first
  },[]);
  const months= useMemo(()=>[...new Set(SEED_DATA.map(d=>d['date'].slice(0,7)))].sort(),[]);

  // Year tab: filtered days
  const yearDays = useMemo(()=>yearFilt==="all"?allDays:allDays.filter(d=>d.date.startsWith(yearFilt)),[allDays,yearFilt]);
  const yearStats= useMemo(()=>standings(yearDays,LB_GAMES,punish),[yearDays,punish]);
  const yearGameStats=useMemo(()=>{
    const out={};
    LB_GAMES.forEach(g=>{out[g]=gamePts(yearDays,g,punish);});
    return out;
  },[yearDays,punish]);

  // Daily tab
  const monthDays = useMemo(()=>allDays.filter(d=>d.date.startsWith(month)),[allDays,month]);
  const selDayData= selDay!=null?monthDays[selDay]:monthDays[monthDays.length-1];
  const daySorted = selDayData?[...PLAYERS].sort((a,b)=>selDayData.all.totals[a]-selDayData.all.totals[b]):[];

  // Games tab
  const gameAllTime = useMemo(()=>gamePts(allDays,selGame,punish),[allDays,selGame,punish]);

  // Trends
  const FORM_DAYS=14;
  const recentDays=useMemo(()=>allDays.slice(-FORM_DAYS),[allDays]);
  const heatmap=useMemo(()=>{
    const h={};
    PLAYERS.forEach(p=>{h[p]={};
      LB_GAMES.forEach(g=>{
        const vals=allDays.map(d=>d.ranks[g]?.[p]??DEFAULT_RANK);
        h[p][g]=parseFloat((vals.reduce((a,b)=>a+b,0)/vals.length).toFixed(2));
      });
    });
    return h;
  },[allDays]);

  const rankColor=avg=>{
    if(avg<=1.8) return{bg:"#dcfce7",tx:"#166534"};
    if(avg<=2.5) return{bg:"#fef9c3",tx:"#854d0e"};
    if(avg<=3.2) return{bg:"#ffedd5",tx:"#9a3412"};
    return{bg:"#fee2e2",tx:"#991b1b"};
  };
  const formColor=r=>{
    if(r===1) return{bg:"#111",tx:"#a3e635"};
    if(r===2) return{bg:"#dcfce7",tx:"#166534"};
    if(r===3) return{bg:"#fef9c3",tx:"#854d0e"};
    if(r===4) return{bg:"#fee2e2",tx:"#991b1b"};
    return{bg:"#f5f5f5",tx:"#ccc"};
  };

  const Av=({p,sz=32})=>(
    <div className="av" style={{width:sz,height:sz,background:P_COLOR[p],fontSize:sz<28?9:10}}>{P_INIT[p]}</div>
  );

  const RB=({r})=><span className={`rb rb${r}`}>{r===5?"–":r}</span>;

  const Cards=({st,label})=>(
    <div className="s-grid">
      {st.sorted.map(p=>{
        const r=st.ranks[p];
        return(
          <div key={p} className={`s-card ${r===1?"gold":""}`}>
            <div className="s-rank">{r}</div>
            <Av p={p} sz={32}/>
            <div className="s-name">{p}</div>
            <div className="s-pts">{st.pts[p]}</div>
            <div className="s-label">{label}</div>
            <div className="s-wins">{st.wins[p]} day win{st.wins[p]!==1?"s":""}</div>
          </div>
        );
      })}
    </div>
  );

  const GameMinis=({gStats})=>(
    <div className="g-grid">
      {LB_GAMES.map(g=>(
        <div key={g} className="g-card">
          <div className="g-hdr">
            <span className="chip" style={{background:GAME_COLOR[g]}}>{GAME_ABBR[g]}</span>
            <span className="g-name">{g}</span>
          </div>
          {gStats[g].sorted.map((p,i)=>(
            <div key={p} className="g-row">
              <span className="g-num">{i+1}</span>
              <div className="dot" style={{background:P_COLOR[p]}}/>
              <span className="g-player">{p}</span>
              <span className="g-pts">{gStats[g].pts[p]}</span>
            </div>
          ))}
        </div>
      ))}
    </div>
  );

  return(<>
    <style>{CSS}</style>
    <div className="app">

      <header className="hdr">
        <div className="hdr-top">
          <div className="logo">Work<em>dle</em></div>
          <div className="hdr-sub">JAN 2023 – MAY 2026<br/>{allDays.length} DAYS</div>
          <button onClick={()=>setPunish(!punish)} style={{
            marginLeft:"auto",flexShrink:0,
            padding:"5px 10px",borderRadius:20,border:"none",cursor:"pointer",
            fontFamily:"'DM Sans',sans-serif",fontSize:11,fontWeight:700,
            background:punish?"#ef4444":"#22c55e",color:"#fff",
            letterSpacing:"0.3px",transition:"background .2s",
          }}>
            {punish?"🏆 Regularity rewarded":"🎯 Skill only"}
          </button>
        </div>
        <nav className="tabs">
          {[["year","🏆 Year"],["scores","📅 Scores"],["games","🎮 Games"],["trends","📊 Trends"],["info","📖 Rules"]].map(([v,l])=>(
            <button key={v} className={`tab ${tab===v?"on":""}`} onClick={()=>setTab(v)}>{l}</button>
          ))}
        </nav>
      </header>

      <div className="body">

        {/* ══ YEAR ══════════════════════════════════════════════════════════ */}
        {tab==="year" && (<>
          {/* Year filter */}
          <div className="filters">
            {years.map(y=>(
              <button key={y} className={`filt ${yearFilt===y?"on":""}`} onClick={()=>setYear(y)}>
                {y==="all"?"All time":y}
              </button>
            ))}
          </div>

          <div className="section">
            <div className="eyebrow">
              {yearFilt==="all"?"All time":yearFilt} · {yearDays.length} days · All 7 games
            </div>
            <Cards st={yearStats} label={yearFilt==="all"?"pts all time":`pts in ${yearFilt}`}/>
          </div>

          <div className="section">
            <div className="eyebrow">Game rankings</div>
            <GameMinis gStats={yearGameStats}/>
          </div>
        </>)}

        {/* ══ DAILY ═════════════════════════════════════════════════════════ */}
        {tab==="scores" && (<>
          {/* Month picker */}
          <div className="filters">
            {allMonths.map(m=>{
              const isEmpty=EMPTY_MONTHS.includes(m);
              const isOn=month===m;
              return(
                <button key={m} disabled={isEmpty}
                  className={`filt ${isOn?"on":""} ${isEmpty?"empty":""}`}
                  onClick={()=>{if(!isEmpty){setMonth(m);setDay(null);}}}>
                  {fmtMonth(m)}{isEmpty?" · no data":""}
                </button>
              );
            })}
          </div>

          {/* Month summary */}
          {(()=>{
            const mStats=standings(monthDays,ALL_GAMES,punish);
            return(<>
              <div className="section">
                <div className="eyebrow">{fmtMonth(month)} · standings · {monthDays.length} days</div>
                <Cards st={mStats} label="pts this month"/>
              </div>
            </>);
          })()}

          {/* Day drill-down */}
          <div className="eyebrow">Drill into a day</div>
          <div className="filters" style={{marginBottom:selDay!=null?16:0}}>
            {monthDays.map((d,i)=>(
              <button key={d.date}
                className={`filt ${selDay===i?"on":""}`}
                onClick={()=>setDay(selDay===i?null:i)}>
                {fmtDate(d.date)}
              </button>
            ))}
          </div>

          {selDay!=null && selDayData && (<>
            <div className="section">
              <div className="eyebrow">{fmtDate(selDayData.date)} · day result</div>
              <div className="day-sum">
                {daySorted.map(p=>{
                  const r=selDayData.all.dayRanks[p];
                  return(
                    <div key={p} className={`dc ${r===1?"gold":""}`}>
                      <div className="dc-rank">{r}</div>
                      <Av p={p} sz={28}/>
                      <div className="dc-name">{p}</div>
                      <div className="dc-pts">{selDayData.all.totals[p]}</div>
                      <div className="dc-sub">pts · 7 games</div>
                    </div>
                  );
                })}
              </div>
            </div>
            <div className="section">
              <div className="eyebrow">Game breakdown</div>
              <div className="tbl">
                <div className="tbl-hdr" style={{gridTemplateColumns:"110px repeat(4,1fr)"}}>
                  <div className="tbl-label">Game</div>
                  {PLAYERS.map(p=>(
                    <div key={p} className="tbl-p-hdr">
                      <div className="dot" style={{background:P_COLOR[p]}}/>
                      {p}
                    </div>
                  ))}
                </div>
                {ALL_GAMES.map(game=>(
                  <div key={game} className="tbl-row" style={{gridTemplateColumns:"110px repeat(4,1fr)"}}>
                    <div className="game-cell">
                      <span className="chip" style={{background:GAME_COLOR[game]}}>{GAME_ABBR[game]}</span>
                      {game}
                    </div>
                    {PLAYERS.map(p=>(
                      <div key={p}><RB r={selDayData.ranks[game]?.[p]??DEFAULT_RANK}/></div>
                    ))}
                  </div>
                ))}
              </div>
            </div>
          </>)}
        </>)}

        {/* ══ GAMES ═════════════════════════════════════════════════════════ */}
        {tab==="games" && (<>
          <div className="filters">
            {ALL_GAMES.map(g=>(
              <button key={g} className={`filt ${selGame===g?"on":""}`} onClick={()=>setGame(g)}>{g}</button>
            ))}
          </div>

          <div className="section">
            <div className="eyebrow">{selGame} · all time ranking</div>
            <div className="s-grid">
              {gameAllTime.sorted.map((p,i)=>{
                const r=i+1;
                return(
                  <div key={p} className={`s-card ${r===1?"gold":""}`}>
                    <div className="s-rank">{r}</div>
                    <Av p={p} sz={32}/>
                    <div className="s-name">{p}</div>
                    <div className="s-pts">{gameAllTime.pts[p]}</div>
                    <div className="s-label">pts ({allDays.length} days)</div>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="section">
            <div className="eyebrow">{selGame} · day by day</div>
            <div className="det-tbl">
              <div className="det-row hdr">
                <div className="tbl-label">Date</div>
                {PLAYERS.map(p=>(
                  <div key={p} className="tbl-p-hdr">
                    <div className="dot" style={{background:P_COLOR[p]}}/>
                    {p}
                  </div>
                ))}
              </div>
              {allDays.map(d=>{
                const gr=d.ranks[selGame];
                const best=Math.min(...PLAYERS.map(p=>gr?.[p]??DEFAULT_RANK));
                return(
                  <div key={d.date} className="det-row">
                    <div className="det-date">{fmtDate(d.date)}</div>
                    {PLAYERS.map(p=>{
                      const r=gr?.[p]??DEFAULT_RANK;
                      return(
                        <div key={p} className="det-cell">
                          <RB r={r}/>
                        </div>
                      );
                    })}
                  </div>
                );
              })}
            </div>
          </div>
        </>)}

        {/* ══ TRENDS ════════════════════════════════════════════════════════ */}
        {tab==="trends" && (<>
          <div className="section">
            <div className="eyebrow">Recent form · last {FORM_DAYS} days · daily rank</div>
            <div className="tbl">
              <div className="form-row" style={{gridTemplateColumns:`52px repeat(${FORM_DAYS},1fr)`,gap:2,background:"#f7f5f0",borderBottom:"1.5px solid #e5e3dc",padding:"7px 10px"}}>
                <div/>
                {recentDays.map(d=>(
                  <div key={d.date} style={{fontSize:8,color:"#ccc",textAlign:"center",fontWeight:600,lineHeight:1.3}}>
                    {fmtDate(d.date).split(" ").map((x,i)=><div key={i}>{x}</div>)}
                  </div>
                ))}
              </div>
              {PLAYERS.map(p=>(
                <div key={p} className="form-row" style={{gridTemplateColumns:`52px repeat(${FORM_DAYS},1fr)`,gap:2,padding:"5px 10px"}}>
                  <div style={{display:"flex",alignItems:"center",gap:4}}>
                    <div className="dot" style={{background:P_COLOR[p]}}/>
                    <span style={{fontSize:11,fontWeight:700}}>{p}</span>
                  </div>
                  {recentDays.map(d=>{
                    const r=d.lb.dayRanks[p]??DEFAULT_RANK;
                    const c=formColor(r);
                    return(
                      <div key={d.date} className="form-cell" style={{background:c.bg,color:c.tx}}>
                        {r===5?"–":r}
                      </div>
                    );
                  })}
                </div>
              ))}
            </div>
          </div>

          <div className="section">
            <div className="eyebrow">Game strengths · avg rank all time · 1 best → 5 worst</div>
            <div className="tbl">
              <div className="heat-row" style={{gridTemplateColumns:`60px repeat(${LB_GAMES.length},1fr)`,gap:4,background:"#f7f5f0",borderBottom:"1.5px solid #e5e3dc",padding:"8px 10px"}}>
                <div/>
                {LB_GAMES.map(g=>(
                  <div key={g} style={{textAlign:"center"}}>
                    <span className="chip" style={{background:GAME_COLOR[g],display:"inline-block",marginBottom:3}}>{GAME_ABBR[g]}</span>
                    <div style={{fontSize:8,color:"#bbb",fontWeight:600}}>{g}</div>
                  </div>
                ))}
              </div>
              {[...PLAYERS].sort((a,b)=>{
                const avg=p=>LB_GAMES.reduce((s,g)=>s+heatmap[p][g],0)/LB_GAMES.length;
                return avg(a)-avg(b);
              }).map(p=>(
                <div key={p} className="heat-row" style={{gridTemplateColumns:`60px repeat(${LB_GAMES.length},1fr)`,gap:4,padding:"6px 10px"}}>
                  <div style={{display:"flex",alignItems:"center",gap:5}}>
                    <div className="dot" style={{background:P_COLOR[p]}}/>
                    <span style={{fontSize:12,fontWeight:700}}>{p}</span>
                  </div>
                  {LB_GAMES.map(g=>{
                    const avg=heatmap[p][g];
                    const c=rankColor(avg);
                    return(
                      <div key={g} className="heat-cell" style={{background:c.bg,color:c.tx}}>
                        <div className="heat-val">{avg.toFixed(1)}</div>
                        <div className="heat-sub">avg</div>
                      </div>
                    );
                  })}
                </div>
              ))}
            </div>
            <div className="legend">
              {[["#dcfce7","#166534","≤1.8 Strong"],["#fef9c3","#854d0e","≤2.5 OK"],["#ffedd5","#9a3412","≤3.2 Weak"],["#fee2e2","#991b1b",">3.2 Struggling"]].map(([bg,tx,label])=>(
                <div key={label} className="leg-item">
                  <div className="leg-dot" style={{background:bg,border:`1px solid ${tx}33`}}/>
                  {label}
                </div>
              ))}
            </div>
          </div>
        </>)}

        {/* ══ RULES ═════════════════════════════════════════════════════════ */}
        {tab==="info" && (<>

          <div className="section">
            <div className="eyebrow">How scoring works</div>
            <div className="tbl">
              {[
                ["Daily ranking","Each day, players are ranked 1–4 within each game. Fastest / fewest guesses = rank 1. Ties share the lower rank (e.g. two players tied for 2nd both get rank 2, next player gets rank 4)."],
                ["Day winner","The player with the lowest total rank across all games that day wins the day."],
                ["Missed a game","If you don't post a score for a game, you get rank 5 — worse than last place. Toggle to 🎯 Skill only to strip out attendance — only games where all 4 players showed up count, so standings reflect pure performance."],
                ["No data at all","If nobody played a game on a given day, that game is skipped entirely and adds nothing to anyone's score."],
                ["Monthly & yearly points","Points accumulate across days. Lower total = better. Think of it like golf."],
              ].map(([title, desc])=>(
                <div key={title} style={{padding:"14px 16px",borderBottom:"1px solid #f2efe8"}}>
                  <div style={{fontSize:13,fontWeight:700,marginBottom:4}}>{title}</div>
                  <div style={{fontSize:12,color:"#666",lineHeight:1.6}}>{desc}</div>
                </div>
              ))}
            </div>
          </div>

          <div className="section">
            <div className="eyebrow">The games</div>
            <div className="tbl">
              {[
                ["Wordle","W","#4ade80","Guess the 5-letter word. Score = number of guesses (1–6). Fail = 7. Lower is better."],
                ["Connections","C","#60a5fa","Group 16 words into 4 categories. Score = total rows used (4 = perfect, each wrong guess adds a row). Fail to complete = 8."],
                ["Tango","T","#a78bfa","LinkedIn logic puzzle. Score = time in seconds. Faster is better."],
                ["Queens","Q","#34d399","Place queens on a grid. Score = time in seconds. Faster is better."],
                ["Pinpoint","Pt","#fbbf24","Guess the category from examples. Score = number of guesses (1–5). Fail = 6."],
                ["Patches","Pa","#f472b6","Sewing-themed puzzle. Score = time in seconds. Faster is better."],
                ["Zip","Z","#fb923c","Connect the dots puzzle. Score = time in seconds. Faster is better."],
              ].map(([name,abbr,color,desc])=>(
                <div key={name} style={{padding:"12px 16px",borderBottom:"1px solid #f2efe8",display:"flex",gap:12,alignItems:"flex-start"}}>
                  <span className="chip" style={{background:color,marginTop:2,flexShrink:0}}>{abbr}</span>
                  <div>
                    <div style={{fontSize:13,fontWeight:700,marginBottom:3}}>{name}</div>
                    <div style={{fontSize:12,color:"#666",lineHeight:1.5}}>{desc}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="section">
            <div className="eyebrow">Data sources</div>
            <div className="tbl">
              {[
                ["WhatsApp chat","Primary source. Scores parsed directly from daily messages in the group chat."],
                ["Google Sheet","Fallback for days not in the chat (Feb 2025 – Jan 2026). Sheet rankings used directly."],
                ["Coverage","Jan–Jun 2023 (Wordle only) · Feb 2025–Jan 2026 (5 games via sheet) · Mar–May 2026 (all 7 games via chat). Jul 2023–Jan 2025 and Sep–Dec 2025 have no data."],
              ].map(([title,desc])=>(
                <div key={title} style={{padding:"14px 16px",borderBottom:"1px solid #f2efe8"}}>
                  <div style={{fontSize:13,fontWeight:700,marginBottom:4}}>{title}</div>
                  <div style={{fontSize:12,color:"#666",lineHeight:1.6}}>{desc}</div>
                </div>
              ))}
            </div>
          </div>

        </>)}

      </div>
    </div>
  </>);
}
